var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"이건 맥크레디의 빙결 능력?","JPN":"これはマクレディーの氷結能力？","ENG":"MacCready's freezing ability?","TWN":"這就是麥克蕾蒂的冰凍能力嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다는 말은…….","JPN":"ということは……","ENG":"Then that means...","TWN":"那就是說……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"후후, 그런건가.","JPN":"ふふ、そういうことか。","ENG":"Haha, is this how this plays out?","TWN":"呵呵，原來如此。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"예상외의 전개로군. 이건 기회가 되겠어.","JPN":"予想外の展開になってきたね。いいチャンスだ。","ENG":"This is unexpected. It could be an opportunity for me.","TWN":"出乎意料的劇情發展啊，應該是個機會。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤을 돌려줘! 돌려 달란 말이야!","JPN":"アンを返して！　返してよ！","ENG":"Give Ann back! I said, give her back!","TWN":"把安妮還給我！還給我！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>이런 개 같은 계집애가……!</color>","JPN":"<color=#ff3636>このうっとうしい小娘……！</color>","ENG":"<color=#ff3636>Why you little brat...!</color>","TWN":"<color=#ff3636>你這個死丫頭……！</color>"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ff3636>방해하지 마! 어서 놓지 못해!?</color>","JPN":"<color=#ff3636>離せ！　邪魔は許さない！</color>","ENG":"<color=#ff3636>Stop interfering! Let go of me!</color>","TWN":"<color=#ff3636>別妨礙我！還不快放手？！</color>"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"피하기에는 늦었어! 받아 칠 수밖에 없나!","JPN":"爆発を避けるにはもう遅い……！　打ち返すしかないのか……！","ENG":"It's too late! I have to deflect it!","TWN":"已經來不及躲開了！只能硬接嗎！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LIAM_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만……!","JPN":"だが……！","ENG":"But…!","TWN":"但是……！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIAM_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이제 끝이네, 버넷.","JPN":"これで終わりだ、バーネット。","ENG":"It's over, Burnett.","TWN":"結束了，伯內特。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"수없이 반복되는 그 날의 기억 속에서.","JPN":"何度も繰り返されるあの日の記憶の中で。","ENG":"Within the countlessly repeating memories of that day.","TWN":"在重複了無數次的那段記憶裡。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"마지막에 떠오르는 것은 폭발에서 우리를 지키려던 요원님의 품과.","JPN":"最後に思い出すのは、爆発から私たちを守ろうとするエージェント様の懐と。","ENG":"The last thing I recall is the agent's arms protecting us from the explosion, and...","TWN":"最後出現的，是在爆炸中守護我們的大人的懷抱……"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"피부로 느껴지는 차가운 쇠사슬.","JPN":"肌に伝わる鎖の冷たさ。","ENG":"the cold chain against my skin.","TWN":"以及那個能切身感受到冰冷的鐵鍊。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 속이 뒤집어질 것만 같은 멀미감이었다.","JPN":"そして吐きそうになる感覚だった。","ENG":"There was also this queasiness, enough to make one sick to the stomach.","TWN":"還有，一種眩暈的感覺。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 다시금 눈을 떴을 때, 내가 마주하는 세계는.","JPN":"やがて気を取り戻した私の目の前に広がる世界は……","ENG":"After, when I opened my eyes, the world I saw was...","TWN":"當我再次睜開眼睛時，面對的世界……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"언제나 끔찍한 풍경의 이곳.","JPN":"終わりのない惨状が広がるこの場所。","ENG":"this horrible landscape.","TWN":"總是慘不忍睹的這裡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……당신은?","JPN":"……あなたは？","ENG":"...You are?","TWN":"……你是？"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"미안해…….","JPN":"悪い……","ENG":"Sorry...","TWN":"對不起……"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 나는 반드시 이번 임무를 성공시켜야만 해.","JPN":"でも、俺は必ず今回の任務を成功させないといけない。","ENG":"But I need to complete this mission no matter what.","TWN":"但我必須要讓這次任務成功。"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 하기로…… 다짐했으니까.","JPN":"そうするって……決めたから。","ENG":"That's what... I promised.","TWN":"就是這樣……因為我已經下定決心了。"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};